import { create } from 'zustand';
import { persist } from 'zustand/middleware';
import type { GanttState, GanttSettings, GanttViewMode, GanttGroupBy, GanttSortBy, Task } from '../types';

interface GanttStore extends GanttState {
  // Settings Actions
  setViewMode: (mode: GanttViewMode) => void;
  toggleCriticalPath: () => void;
  toggleBaseline: () => void;
  toggleResources: () => void;
  setZoomLevel: (level: number) => void;
  setGroupBy: (groupBy: GanttGroupBy) => void;
  setSortBy: (sortBy: GanttSortBy) => void;

  // Selection Actions
  selectTask: (taskId: string) => void;
  deselectTask: (taskId: string) => void;
  clearSelection: () => void;
  toggleTaskSelection: (taskId: string) => void;

  // Critical Path Actions
  calculateCriticalPath: (tasks: Task[]) => void;
  isTaskOnCriticalPath: (taskId: string) => boolean;

  // Date Range Actions
  updateDateRange: (tasks: Task[]) => void;

  // Reset
  resetSettings: () => void;
}

const defaultSettings: GanttSettings = {
  viewMode: 'week',
  showCriticalPath: true,
  showBaseline: false,
  showResources: true,
  zoomLevel: 3,
  groupBy: 'none',
  sortBy: 'start-date',
};

export const useGanttStore = create<GanttStore>()(
  persist(
    (set, get) => ({
      settings: defaultSettings,
      selectedTaskIds: [],
      criticalPath: [],
      earliestStart: null,
      latestFinish: null,

      // Settings Actions
      setViewMode: (mode) =>
        set((state) => ({
          settings: { ...state.settings, viewMode: mode },
        })),

      toggleCriticalPath: () =>
        set((state) => ({
          settings: {
            ...state.settings,
            showCriticalPath: !state.settings.showCriticalPath,
          },
        })),

      toggleBaseline: () =>
        set((state) => ({
          settings: {
            ...state.settings,
            showBaseline: !state.settings.showBaseline,
          },
        })),

      toggleResources: () =>
        set((state) => ({
          settings: {
            ...state.settings,
            showResources: !state.settings.showResources,
          },
        })),

      setZoomLevel: (level) =>
        set((state) => ({
          settings: {
            ...state.settings,
            zoomLevel: Math.min(5, Math.max(1, level)),
          },
        })),

      setGroupBy: (groupBy) =>
        set((state) => ({
          settings: { ...state.settings, groupBy },
        })),

      setSortBy: (sortBy) =>
        set((state) => ({
          settings: { ...state.settings, sortBy },
        })),

      // Selection Actions
      selectTask: (taskId) =>
        set((state) => ({
          selectedTaskIds: [...state.selectedTaskIds, taskId],
        })),

      deselectTask: (taskId) =>
        set((state) => ({
          selectedTaskIds: state.selectedTaskIds.filter((id) => id !== taskId),
        })),

      clearSelection: () =>
        set({ selectedTaskIds: [] }),

      toggleTaskSelection: (taskId) => {
        const { selectedTaskIds } = get();
        if (selectedTaskIds.includes(taskId)) {
          get().deselectTask(taskId);
        } else {
          get().selectTask(taskId);
        }
      },

      // Critical Path Calculation (Simplified for MVP)
      calculateCriticalPath: (tasks) => {
        // This is a simplified critical path calculation
        // Full CPM algorithm would be more complex

        // Filter tasks with dates
        const tasksWithDates = tasks.filter(
          (task) => task.startDate && task.dueDate
        );

        if (tasksWithDates.length === 0) {
          set({ criticalPath: [] });
          return;
        }

        // Build dependency graph
        const graph = new Map<string, string[]>();
        const inDegree = new Map<string, number>();

        tasksWithDates.forEach((task) => {
          if (!graph.has(task.id)) {
            graph.set(task.id, []);
          }
          if (!inDegree.has(task.id)) {
            inDegree.set(task.id, 0);
          }

          task.dependencies?.forEach((dep) => {
            const predecessorId = dep.taskId;
            if (!graph.has(predecessorId)) {
              graph.set(predecessorId, []);
            }
            graph.get(predecessorId)?.push(task.id);
            inDegree.set(task.id, (inDegree.get(task.id) || 0) + 1);
          });
        });

        // Calculate earliest finish times
        const earliestFinish = new Map<string, Date>();
        const queue: string[] = [];

        // Start with tasks that have no dependencies
        tasksWithDates.forEach((task) => {
          if ((inDegree.get(task.id) || 0) === 0) {
            queue.push(task.id);
            earliestFinish.set(task.id, new Date(task.dueDate!));
          }
        });

        while (queue.length > 0) {
          const currentId = queue.shift()!;
          const successors = graph.get(currentId) || [];

          successors.forEach((successorId) => {
            const currentFinish = earliestFinish.get(currentId)!;
            const existingFinish = earliestFinish.get(successorId);

            if (!existingFinish || currentFinish > existingFinish) {
              const successor = tasksWithDates.find((t) => t.id === successorId);
              if (successor) {
                earliestFinish.set(successorId, new Date(successor.dueDate!));
              }
            }

            // Decrease in-degree
            inDegree.set(successorId, (inDegree.get(successorId) || 0) - 1);
            if (inDegree.get(successorId) === 0) {
              queue.push(successorId);
            }
          });
        }

        // For MVP: Mark longest path as critical path
        // In full implementation, would calculate slack and find zero-slack tasks
        const pathLengths = new Map<string, number>();

        const calculatePathLength = (taskId: string, visited = new Set<string>()): number => {
          if (visited.has(taskId)) return 0;
          if (pathLengths.has(taskId)) return pathLengths.get(taskId)!;

          visited.add(taskId);
          const task = tasksWithDates.find((t) => t.id === taskId);
          if (!task || !task.dependencies || task.dependencies.length === 0) {
            pathLengths.set(taskId, 1);
            return 1;
          }

          const maxPredecessorLength = Math.max(
            ...task.dependencies.map((dep) =>
              calculatePathLength(dep.taskId, new Set(visited))
            )
          );

          const length = maxPredecessorLength + 1;
          pathLengths.set(taskId, length);
          return length;
        };

        tasksWithDates.forEach((task) => {
          calculatePathLength(task.id);
        });

        // Find tasks on longest path
        const maxLength = Math.max(...Array.from(pathLengths.values()));
        const criticalTasks = tasksWithDates
          .filter((task) => pathLengths.get(task.id) === maxLength)
          .map((task) => task.id);

        set({ criticalPath: criticalTasks });
      },

      isTaskOnCriticalPath: (taskId) => {
        return get().criticalPath.includes(taskId);
      },

      // Date Range Calculation
      updateDateRange: (tasks) => {
        const tasksWithDates = tasks.filter(
          (task) => task.startDate && task.dueDate
        );

        if (tasksWithDates.length === 0) {
          set({ earliestStart: null, latestFinish: null });
          return;
        }

        const startDates = tasksWithDates.map((task) => new Date(task.startDate!));
        const endDates = tasksWithDates.map((task) => new Date(task.dueDate!));

        const earliestStart = new Date(Math.min(...startDates.map((d) => d.getTime())));
        const latestFinish = new Date(Math.max(...endDates.map((d) => d.getTime())));

        set({
          earliestStart: earliestStart.toISOString(),
          latestFinish: latestFinish.toISOString(),
        });
      },

      // Reset
      resetSettings: () =>
        set({
          settings: defaultSettings,
          selectedTaskIds: [],
        }),
    }),
    {
      name: 'gantt-storage',
      partialize: (state) => ({
        settings: state.settings,
        // Don't persist selectedTaskIds or calculated fields
      }),
    }
  )
);

# Gantt Chart Widget Specification

**Created:** November 2025
**Target Implementation:** Q2-Q3 2026
**Estimated Effort:** 40-50 hours
**Priority:** P1 - High Impact
**Status:** Specification Complete - Ready for Implementation

---

## 📋 Overview

Transform Neuman Brain into a professional project management platform by adding Gantt chart capabilities. This widget will provide timeline visualization with task dependencies, critical path analysis, and resource allocation views.

**Why Gantt Charts?** Essential for professional PM - visualize project timelines, identify bottlenecks, manage dependencies, and track critical paths.

---

## 🎯 Goals

### Primary Goals
1. **Timeline Visualization** - Display Kanban tasks on a calendar timeline
2. **Dependency Management** - Link tasks with dependency relationships
3. **Critical Path** - Auto-calculate and highlight critical path
4. **Date Management** - Drag to adjust task start/end dates
5. **Milestone Tracking** - Visual milestone markers

### Secondary Goals
1. **Resource Overlay** - Show who's assigned to what
2. **Baseline Comparison** - Compare planned vs actual
3. **Export** - Export Gantt chart as PNG/PDF
4. **Zoom Controls** - Day/week/month/quarter views

---

## 🏗️ Architecture

### Data Flow

```
┌──────────────────────────────────────────────────────────┐
│                    User Interaction                       │
└──────────────────┬───────────────────────────────────────┘
                   │
         ┌─────────▼──────────┐
         │  Gantt Widget      │
         │  (React Component) │
         └─────────┬──────────┘
                   │
         ┌─────────▼──────────┐
         │  useKanbanStore    │ ← Existing store (reads tasks)
         │  (Task Data)       │
         └─────────┬──────────┘
                   │
         ┌─────────▼──────────┐
         │  Enhanced Task     │
         │  (with dependencies)│
         └────────────────────┘
```

### Component Hierarchy

```
Gantt.tsx (Main widget)
├── GanttToolbar.tsx (View controls, zoom, today button)
├── GanttTimeline.tsx (Timeline header with dates)
├── GanttGrid.tsx (Task grid)
│   ├── GanttRow.tsx (Individual task row)
│   │   ├── GanttBar.tsx (Visual task bar)
│   │   └── GanttMilestone.tsx (Diamond marker)
│   └── GanttDependencyLine.tsx (Arrow between tasks)
└── GanttCriticalPath.tsx (Highlighted critical path)
```

---

## 🗃️ Data Model Extensions

### Enhanced Task Type

```typescript
// Add to src/types/index.ts

export type DependencyType =
  | 'finish-to-start'  // Task B starts when A finishes (default)
  | 'start-to-start'   // Task B starts when A starts
  | 'finish-to-finish' // Task B finishes when A finishes
  | 'start-to-finish'; // Task B finishes when A starts (rare)

export interface TaskDependency {
  taskId: string;           // ID of dependent task
  type: DependencyType;     // Type of dependency
  lag: number;              // Lag time in days (can be negative for lead)
}

export interface Task {
  // ... existing fields
  id: string;
  title: string;
  description: string;
  status: TaskStatus;
  created: string;
  startDate: string | null;  // EXISTING
  dueDate: string | null;    // EXISTING
  priority: TaskPriority;
  tags: string[];
  order?: number;

  // NEW FIELDS FOR GANTT:
  dependencies: TaskDependency[]; // Tasks this depends on
  estimatedHours: number;         // For resource planning
  actualHours: number;            // For EVM calculations
  progress: number;               // 0-100 percentage complete
  isMilestone: boolean;           // True for milestone markers
  assignedTo?: string;            // Resource ID
  baseline?: {                    // Original plan for comparison
    startDate: string;
    dueDate: string;
  };
  isOnCriticalPath?: boolean;     // Calculated field
}
```

### New Gantt Store

```typescript
// src/stores/useGanttStore.ts

export interface GanttSettings {
  viewMode: 'day' | 'week' | 'month' | 'quarter';
  showCriticalPath: boolean;
  showBaseline: boolean;
  showResources: boolean;
  zoomLevel: number; // 1-5
  groupBy: 'status' | 'priority' | 'assignee' | 'none';
  sortBy: 'start-date' | 'due-date' | 'priority' | 'manual';
}

export interface GanttState {
  settings: GanttSettings;
  selectedTaskIds: string[];
  criticalPath: string[]; // Task IDs on critical path
  earliestStart: Date;    // Calculated from all tasks
  latestFinish: Date;     // Calculated from all tasks
}

export interface GanttStore extends GanttState {
  setViewMode: (mode: GanttSettings['viewMode']) => void;
  toggleCriticalPath: () => void;
  selectTask: (taskId: string) => void;
  deselectTask: (taskId: string) => void;
  calculateCriticalPath: () => void;
  updateTaskDates: (taskId: string, start: string, end: string) => void;
  addDependency: (taskId: string, dependsOn: string, type: DependencyType) => void;
  removeDependency: (taskId: string, dependsOn: string) => void;
}
```

---

## 🛠️ Implementation Phases

### **Phase 1: Foundation** (Week 1, 8-10 hours)

**Goal:** Basic timeline visualization of existing tasks

**Tasks:**
- [ ] Install Gantt library (`frappe-gantt` or build custom with D3)
- [ ] Create `src/widgets/Gantt.tsx` skeleton
- [ ] Create `src/stores/useGanttStore.ts`
- [ ] Read tasks from `useKanbanStore`
- [ ] Render tasks on timeline (start date to due date)
- [ ] Basic toolbar (today button, zoom controls)

**Files to Create:**
```
src/widgets/Gantt.tsx
src/stores/useGanttStore.ts
src/widgets/Gantt/GanttToolbar.tsx
src/widgets/Gantt/GanttTimeline.tsx
src/widgets/Gantt/GanttGrid.tsx
```

**Acceptance Criteria:**
- ✅ Gantt widget loads without errors
- ✅ All Kanban tasks with dates appear on timeline
- ✅ Timeline shows correct date range
- ✅ "Today" line visible
- ✅ Zoom in/out changes time scale

---

### **Phase 2: Dependencies** (Week 2, 10-12 hours)

**Goal:** Add task dependencies with visual arrows

**Tasks:**
- [ ] Extend Task type with `dependencies` field
- [ ] Update `useKanbanStore` actions to handle dependencies
- [ ] Create `GanttDependencyLine.tsx` component
- [ ] Draw arrows between dependent tasks
- [ ] Add dependency creation UI (drag from task to task)
- [ ] Add dependency removal UI (click arrow to delete)
- [ ] Validate no circular dependencies

**Algorithm for Dependency Lines:**
```typescript
// Calculate SVG path from task A to task B
function calculateDependencyPath(
  taskA: Task,
  taskB: Task,
  type: DependencyType
): string {
  const startPoint = getConnectionPoint(taskA, type);
  const endPoint = getConnectionPoint(taskB, type);

  // Create elbow-shaped arrow path
  return `M ${startPoint.x},${startPoint.y}
          L ${(startPoint.x + endPoint.x) / 2},${startPoint.y}
          L ${(startPoint.x + endPoint.x) / 2},${endPoint.y}
          L ${endPoint.x},${endPoint.y}`;
}
```

**Acceptance Criteria:**
- ✅ Can add dependency by dragging between tasks
- ✅ Arrow renders correctly between dependent tasks
- ✅ Can delete dependency by clicking arrow
- ✅ Circular dependency validation works
- ✅ Different arrow styles for dependency types

---

### **Phase 3: Critical Path** (Week 3, 8-10 hours)

**Goal:** Calculate and highlight critical path

**Tasks:**
- [ ] Implement Critical Path Method (CPM) algorithm
- [ ] Calculate earliest start/finish times
- [ ] Calculate latest start/finish times
- [ ] Calculate slack/float for each task
- [ ] Identify tasks with zero slack (critical path)
- [ ] Highlight critical path tasks (red border/background)
- [ ] Add toggle to show/hide critical path

**Critical Path Algorithm:**
```typescript
function calculateCriticalPath(tasks: Task[]): string[] {
  // 1. Topological sort of tasks by dependencies
  const sortedTasks = topologicalSort(tasks);

  // 2. Forward pass: Calculate earliest start/finish
  const earliest = new Map<string, { start: Date; finish: Date }>();
  for (const task of sortedTasks) {
    const deps = task.dependencies || [];
    const earliestStart = deps.length === 0
      ? task.startDate
      : Math.max(...deps.map(d => earliest.get(d.taskId).finish));

    earliest.set(task.id, {
      start: earliestStart,
      finish: addDays(earliestStart, task.duration)
    });
  }

  // 3. Backward pass: Calculate latest start/finish
  const latest = new Map<string, { start: Date; finish: Date }>();
  for (const task of sortedTasks.reverse()) {
    // ... calculate latest times
  }

  // 4. Calculate slack (float)
  const slack = new Map<string, number>();
  for (const task of tasks) {
    slack.set(task.id, latest.get(task.id).start - earliest.get(task.id).start);
  }

  // 5. Critical path = tasks with zero slack
  return tasks
    .filter(t => slack.get(t.id) === 0)
    .map(t => t.id);
}
```

**Acceptance Criteria:**
- ✅ Critical path calculation is accurate
- ✅ Critical tasks highlighted in red
- ✅ Toggle button shows/hides critical path
- ✅ Critical path updates when dependencies change
- ✅ Critical path updates when dates change

---

### **Phase 4: Drag-to-Adjust** (Week 4, 8-10 hours)

**Goal:** Drag task bars to adjust dates

**Tasks:**
- [ ] Make Gantt bars draggable
- [ ] Drag left/right to move entire task
- [ ] Drag edges to resize (change start/end date)
- [ ] Update `useKanbanStore` when dates change
- [ ] Cascade date changes to dependent tasks
- [ ] Show tooltip with new dates while dragging
- [ ] Add undo/redo for date changes

**Drag Logic:**
```typescript
function handleTaskDrag(
  taskId: string,
  deltaX: number, // Pixels moved
  pixelsPerDay: number
) {
  const daysChanged = Math.round(deltaX / pixelsPerDay);
  const task = useKanbanStore.getState().tasks.find(t => t.id === taskId);

  const newStart = addDays(parseDate(task.startDate), daysChanged);
  const newDue = addDays(parseDate(task.dueDate), daysChanged);

  useKanbanStore.getState().updateTask(taskId, {
    startDate: formatDate(newStart),
    dueDate: formatDate(newDue)
  });

  // Cascade to dependent tasks
  const dependentTasks = findDependentTasks(taskId);
  for (const depTask of dependentTasks) {
    updateDependentTaskDates(depTask, task);
  }
}
```

**Acceptance Criteria:**
- ✅ Can drag task bar left/right to move
- ✅ Can drag edges to resize
- ✅ Tooltip shows new dates while dragging
- ✅ Changes save to Kanban store
- ✅ Dependent tasks update automatically
- ✅ Undo/redo works

---

### **Phase 5: Milestones & Polish** (Week 5, 6-8 hours)

**Goal:** Add milestones and final polish

**Tasks:**
- [ ] Add `isMilestone` flag to Task type
- [ ] Render milestones as diamond markers
- [ ] Add milestone creation from context menu
- [ ] Add progress bars within task bars
- [ ] Add today indicator line
- [ ] Add grid lines for better readability
- [ ] Add task labels (task title on bar)
- [ ] Responsive design for mobile

**Milestone Rendering:**
```typescript
// Diamond shape for milestone
<svg>
  <path d="M 0,10 L 10,0 L 20,10 L 10,20 Z" fill="gold" />
</svg>
```

**Acceptance Criteria:**
- ✅ Milestones render as diamonds
- ✅ Progress bars show completion %
- ✅ Today line is visible
- ✅ Grid lines improve readability
- ✅ Task titles visible on bars
- ✅ Works on mobile (horizontal scroll)

---

### **Phase 6: Advanced Features** (Week 6, 6-8 hours)

**Goal:** Add professional features

**Tasks:**
- [ ] Baseline comparison (show original plan vs current)
- [ ] Resource allocation view (group by assignee)
- [ ] Export to PNG/PDF
- [ ] Print view
- [ ] Custom colors per task/project
- [ ] Keyboard shortcuts (arrow keys to navigate)

**Baseline Rendering:**
```typescript
// Show baseline as gray bar below current bar
<rect
  x={baselineStartX}
  y={y + barHeight + 2}
  width={baselineWidth}
  height={4}
  fill="gray"
  opacity={0.5}
/>
```

**Acceptance Criteria:**
- ✅ Baseline shows original plan
- ✅ Can group by resource
- ✅ Export to PNG works
- ✅ Print view formatted correctly
- ✅ Custom colors work
- ✅ Keyboard shortcuts work

