    18→  const tasks = useKanbanStore((state) => state.tasks);
    19→  const updateTask = useKanbanStore((state) => state.updateTask);
    20→  const getCriticalPath = useKanbanStore((state) => state.getCriticalPath);
    21→  const setBaseline = useKanbanStore((state) => state.setBaseline);
    22→  const clearBaseline = useKanbanStore((state) => state.clearBaseline);
    23→  const baseline = useKanbanStore((state) => state.baseline);
    24→
    25→  const [zoom, setZoom] = useState<ZoomLevel>('week');
    26→  const [showCriticalPath, setShowCriticalPath] = useState(false);
    27→
    28→  // Phase 1.3: Calculate critical path
