     1→/**
     2→ * GanttTimeline Component
     3→ * Main SVG timeline canvas with task bars and grid
     4→ * Phase 7: Enhanced with dependent task shift confirmation
     5→ */
     6→
     7→import { useRef, useEffect, useState } from 'react';
     8→import { Download } from 'lucide-react';
     9→import type { Task, TaskStatus, ProjectBaseline } from '../../types';
    10→import { TimelineScale } from './TimelineScale';
    11→import { TaskBar } from './TaskBar';
    12→import { DependencyLine } from './DependencyLine';
    13→import { ExportDialog } from './ExportDialog';
    14→import { DependentShiftDialog } from './DependentShiftDialog';
    15→import { ROW_HEIGHT, dateToX, type ZoomLevel } from './utils';
    16→import { getBaselineTask } from '../../utils/baseline';
    17→import { useKanbanStore } from '../../stores/useKanbanStore';
    18→
    19→interface TaskShift {
    20→  taskId: string;
    21→  newStartDate: string | null;
    22→  newDueDate: string | null;
    23→  reason: string;
    24→}
    25→
    26→interface GanttTimelineProps {
    27→  tasks: Task[];
    28→  startDate: Date;
    29→  endDate: Date;
    30→  zoom: ZoomLevel;
    31→  onTaskUpdate: (taskId: string, updates: Partial<Task>) => void;
    32→  onTaskClick: (task: Task) => void;
    33→  criticalTaskIds?: string[]; // Phase 1.3: Critical path
    34→  baseline?: ProjectBaseline | null; // Phase 1.4: Baseline comparison
    35→}
    36→
    37→export function GanttTimeline({
    38→  tasks,
    39→  startDate,
    40→  endDate,
    41→  zoom,
    42→  onTaskUpdate,
    43→  onTaskClick,
    44→  criticalTaskIds = [],
    45→  baseline = null,
    46→}: GanttTimelineProps) {
    47→  const containerRef = useRef<HTMLDivElement>(null);
    48→  const timelineRef = useRef<HTMLDivElement>(null);
    49→  const [containerWidth, setContainerWidth] = useState(0);
    50→  const [isExportDialogOpen, setIsExportDialogOpen] = useState(false);
    51→  const [expandedTaskIds, setExpandedTaskIds] = useState<Set<string>>(new Set());
    52→
    53→  // Phase 7: Dependent shift confirmation state
    54→  const [pendingShifts, setPendingShifts] = useState<TaskShift[]>([]);
    55→  const [isShiftDialogOpen, setIsShiftDialogOpen] = useState(false);
    56→  const applyDependentShifts = useKanbanStore((state) => state.applyDependentShifts);
    57→
    58→  // Calculate timeline width based on date range
    59→  const timelineWidth = dateToX(endDate, startDate, zoom);
    60→
    61→  // Update container width on resize
    62→  useEffect(() => {
    63→    if (!containerRef.current) return;
    64→
    65→    const updateWidth = () => {
    66→      if (containerRef.current) {
    67→        setContainerWidth(containerRef.current.clientWidth);
    68→      }
    69→    };
    70→
    71→    updateWidth();
    72→
    73→    const observer = new ResizeObserver(updateWidth);
    74→    observer.observe(containerRef.current);
    75→
    76→    return () => observer.disconnect();
    77→  }, []);
    78→
    79→  // Group tasks by status (swimlanes)
    80→  const groupedTasks = tasks.reduce((acc, task) => {
    81→    if (!acc[task.status]) {
    82→      acc[task.status] = [];
    83→    }
    84→    acc[task.status].push(task);
    85→    return acc;
    86→  }, {} as Record<TaskStatus, Task[]>);
    87→
    88→  const statuses: TaskStatus[] = ['backlog', 'todo', 'inprogress', 'review', 'done'];
    89→  const swimlanes = statuses.map((status) => ({
    90→    status,
    91→    tasks: groupedTasks[status] || [],
    92→  }));
    93→
    94→  // Calculate today marker position
    95→  const todayX = dateToX(new Date(), startDate, zoom);
    96→  const isTodayVisible = todayX >= 0 && todayX <= timelineWidth;
    97→
    98→  // Create task lookup map for dependency rendering
    99→  const taskMap = new Map(tasks.map((task) => [task.id, task]));
   100→
   101→  // Create task position map (task ID -> row index)
   102→  const taskRowMap = new Map<string, number>();
   103→  swimlanes.forEach((swimlane, swimlaneIndex) => {
   104→    swimlane.tasks.forEach((task) => {
   105→      taskRowMap.set(task.id, swimlaneIndex);
   106→    });
   107→  });
   108→
   109→  // Status labels
   110→  const getStatusLabel = (status: TaskStatus): string => {
   111→    switch (status) {
   112→      case 'backlog':
   113→        return 'Backlog';
   114→      case 'todo':
   115→        return 'To Do';
   116→      case 'inprogress':
   117→        return 'In Progress';
   118→      case 'review':
   119→        return 'In Review';
   120→      case 'done':
   121→        return 'Done';
   122→      default:
   123→        return status;
   124→    }
   125→  };
   126→
   127→  // Helper: Convert subtasks to full Task objects with hierarchy
   128→  interface TaskWithHierarchy extends Task {
   129→    level: number;
   130→    parentId?: string;
   131→    hasSubtasks: boolean;
   132→  }
   133→
   134→  const buildTaskHierarchy = (tasks: Task[]): TaskWithHierarchy[] => {
   135→    const result: TaskWithHierarchy[] = [];
   136→
   137→    tasks.forEach((task) => {
   138→      // Add parent task
   139→      result.push({
   140→        ...task,
   141→        level: 0,
   142→        hasSubtasks: !!task.subtasks && task.subtasks.length > 0,
   143→      });
   144→
   145→      // Add subtasks if parent is expanded
   146→      if (task.subtasks && task.subtasks.length > 0 && expandedTaskIds.has(task.id)) {
