     1→/**
     2→ * Gantt View Utilities
     3→ * Date calculations and positioning algorithms for timeline rendering
     4→ */
     5→
     6→import { differenceInDays, addDays, startOfDay, endOfDay } from 'date-fns';
     7→
     8→export type ZoomLevel = 'day' | 'week' | 'month';
     9→
    10→/**
    11→ * Pixels per day for each zoom level
    12→ */
    13→export const PIXELS_PER_DAY: Record<ZoomLevel, number> = {
    14→  day: 40,
    15→  week: 8,
    16→  month: 2,
    17→};
    18→
    19→/**
    20→ * Row height for swimlanes
    21→ */
    22→export const ROW_HEIGHT = 60;
    23→
    24→/**
    25→ * Header height for timeline scale
    26→ */
    27→export const HEADER_HEIGHT = 50;
    28→
    29→/**
    30→ * Task bar height within row
    31→ */
    32→export const TASK_BAR_HEIGHT = 40;
    33→
    34→/**
    35→ * Convert date to pixel position on timeline
    36→ */
    37→export function dateToX(
    38→  date: Date,
    39→  scaleStart: Date,
    40→  zoom: ZoomLevel
    41→): number {
    42→  const daysDiff = differenceInDays(startOfDay(date), startOfDay(scaleStart));
    43→  return daysDiff * PIXELS_PER_DAY[zoom];
    44→}
    45→
    46→/**
    47→ * Convert pixel position to date
    48→ */
    49→export function xToDate(
    50→  x: number,
    51→  scaleStart: Date,
    52→  zoom: ZoomLevel
    53→): Date {
    54→  const days = Math.round(x / PIXELS_PER_DAY[zoom]);
    55→  return addDays(scaleStart, days);
    56→}
    57→
    58→/**
    59→ * Calculate task bar width from start/end dates
    60→ */
    61→export function calculateBarWidth(
    62→  startDate: Date,
    63→  endDate: Date,
    64→  zoom: ZoomLevel
    65→): number {
    66→  const days = differenceInDays(endOfDay(endDate), startOfDay(startDate));
    67→  // Minimum 1 day width
    68→  return Math.max(days + 1, 1) * PIXELS_PER_DAY[zoom];
    69→}
    70→
    71→/**
    72→ * Get timeline bounds (start/end dates) based on tasks
    73→ * Adds padding before/after for better UX
    74→ */
    75→export function getTimelineBounds(tasks: Array<{ startDate?: string | null; dueDate?: string | null }>) {
    76→  const dates: Date[] = [];
    77→
    78→  tasks.forEach((task) => {
    79→    if (task.startDate && task.startDate !== null) dates.push(new Date(task.startDate));
    80→    if (task.dueDate && task.dueDate !== null) dates.push(new Date(task.dueDate));
    81→  });
    82→
    83→  if (dates.length === 0) {
    84→    // Default to 30 days centered on today
    85→    const today = new Date();
    86→    return {
    87→      start: addDays(today, -15),
    88→      end: addDays(today, 15),
    89→    };
    90→  }
    91→
    92→  // Find min/max dates and add padding
    93→  const minDate = new Date(Math.min(...dates.map((d) => d.getTime())));
    94→  const maxDate = new Date(Math.max(...dates.map((d) => d.getTime())));
    95→
    96→  return {
    97→    start: addDays(minDate, -7), // 1 week padding before
    98→    end: addDays(maxDate, 7), // 1 week padding after
    99→  };
   100→}
   101→
   102→/**
   103→ * Get default start date for task with only due date
   104→ * Assumes 1-day duration
   105→ */
   106→export function getDefaultStartDate(dueDate: Date): Date {
   107→  return startOfDay(dueDate);
   108→}
   109→
   110→/**
   111→ * Get default due date for task with only start date
   112→ * Assumes 1-day duration
   113→ */
   114→export function getDefaultDueDate(startDate: Date): Date {
   115→  return endOfDay(startDate);
   116→}
