   136→        case 'start-to-finish':
   137→          // This task must finish when dep starts, so work backwards
   138→          depFinish = depSchedule.earliestStart + (dep.lag || 0) - schedules.get(taskId)!.duration;
   139→          break;
   140→      }
   141→
   142→      maxEarliestFinish = Math.max(maxEarliestFinish, depFinish);
   143→    });
   144→
   145→    const schedule = schedules.get(taskId)!;
   146→    schedule.earliestStart = maxEarliestFinish;
   147→    schedule.earliestFinish = schedule.earliestStart + schedule.duration;
   148→
   149→    processed.add(taskId);
   150→  }
   151→
   152→  // Process all tasks
   153→  tasks.forEach(task => processTask(task.id));
   154→
   155→  return schedules;
   156→}
   157→
   158→/**
   159→ * Backward pass: Calculate latest start/finish for each task
   160→ */
   161→function backwardPass(
   162→  tasks: Task[],
   163→  schedules: Map<string, TaskSchedule>,
   164→  graph: Map<string, string[]>
   165→): void {
   166→  // Find project end (latest earliestFinish)
   167→  let projectEnd = 0;
   168→  schedules.forEach(schedule => {
   169→    projectEnd = Math.max(projectEnd, schedule.earliestFinish);
   170→  });
   171→
   172→  // Initialize all tasks with project end
   173→  const processed = new Set<string>();
   174→
   175→  // Start from tasks with no dependents
   176→  function processTask(taskId: string) {
   177→    if (processed.has(taskId)) return;
   178→
   179→    const task = tasks.find(t => t.id === taskId);
   180→    if (!task) return;
   181→
   182→    const dependents = graph.get(taskId) || [];
   183→
   184→    // Process all dependents first
   185→    dependents.forEach(depId => {
   186→      processTask(depId);
   187→    });
   188→
   189→    const schedule = schedules.get(taskId)!;
   190→
   191→    if (dependents.length === 0) {
   192→      // No dependents - can finish at project end
   193→      schedule.latestFinish = projectEnd;
   194→      schedule.latestStart = schedule.latestFinish - schedule.duration;
   195→    } else {
   196→      // Calculate latest finish based on dependents
   197→      let minLatestStart = Infinity;
   198→
   199→      dependents.forEach(depId => {
   200→        const dependent = tasks.find(t => t.id === depId);
   201→        if (!dependent) return;
   202→
   203→        const depSchedule = schedules.get(depId);
   204→        if (!depSchedule) return;
   205→
   206→        const dependency = dependent.dependencies?.find(d => d.taskId === taskId);
   207→        if (!dependency) return;
   208→
   209→        let latestFinish = 0;
   210→        switch (dependency.type) {
   211→          case 'finish-to-start':
   212→            latestFinish = depSchedule.latestStart - (dependency.lag || 0);
   213→            break;
   214→          case 'start-to-start':
   215→            latestFinish = depSchedule.latestStart - (dependency.lag || 0) + schedule.duration;
   216→            break;
   217→          case 'finish-to-finish':
   218→            latestFinish = depSchedule.latestFinish - (dependency.lag || 0);
   219→            break;
   220→          case 'start-to-finish':
   221→            latestFinish = depSchedule.latestFinish - (dependency.lag || 0) + schedule.duration;
   222→            break;
   223→        }
   224→
   225→        minLatestStart = Math.min(minLatestStart, latestFinish - schedule.duration);
   226→      });
