   228→      schedule.latestStart = minLatestStart === Infinity ? schedule.earliestStart : minLatestStart;
   229→      schedule.latestFinish = schedule.latestStart + schedule.duration;
   230→    }
   231→
   232→    // Calculate slack
   233→    schedule.slack = schedule.latestStart - schedule.earliestStart;
   234→
   235→    processed.add(taskId);
   236→  }
   237→
   238→  // Process all tasks from the end
   239→  tasks.forEach(task => processTask(task.id));
