   242→/**
   243→ * Calculate critical path for a set of tasks
   244→ * @returns Array of task IDs on critical path
   245→ */
   246→export function calculateCriticalPath(tasks: Task[]): string[] {
   247→  if (tasks.length === 0) return [];
   248→
   249→  // Filter to tasks with dates
   250→  const tasksWithDates = tasks.filter(t => t.startDate || t.dueDate);
   251→  if (tasksWithDates.length === 0) return [];
   252→
   253→  log.info(`Calculating critical path for ${tasksWithDates.length} tasks`);
   254→
   255→  // Find project start date
   256→  let projectStart: Date | null = null;
   257→  tasksWithDates.forEach(task => {
   258→    if (task.startDate) {
   259→      const [year, month, day] = task.startDate.split('-').map(Number);
   260→      const date = new Date(year, month - 1, day);
   261→      if (!projectStart || date < projectStart) {
   262→        projectStart = date;
   263→      }
   264→    }
   265→  });
   266→
   267→  if (!projectStart) {
   268→    projectStart = new Date(); // Fallback to today
   269→  }
   270→
   271→  // Build dependency graph
   272→  const graph = buildDependencyGraph(tasksWithDates);
   273→
   274→  // Forward pass
   275→  const schedules = forwardPass(tasksWithDates, projectStart, graph);
   276→
   277→  // Backward pass
   278→  backwardPass(tasksWithDates, schedules, graph);
   279→
   280→  // Find critical tasks (slack = 0)
   281→  const criticalTasks: string[] = [];
   282→  schedules.forEach((schedule, taskId) => {
   283→    if (Math.abs(schedule.slack) < 0.1) { // Allow small floating point error
   284→      criticalTasks.push(taskId);
   285→    }
   286→  });
   287→
   288→  log.info(`Critical path identified: ${criticalTasks.length} tasks`, { criticalTasks });
   289→
   290→  return criticalTasks;
   291→}
   292→
   293→/**
   294→ * Calculate slack time for a specific task
   295→ * @returns Number of days task can be delayed without affecting project end
   296→ */
   297→export function calculateSlack(task: Task, allTasks: Task[]): number {
   298→  if (!task.startDate || !task.dueDate) return 0;
   299→
   300→  // Find project start
   301→  let projectStart: Date | null = null;
   302→  allTasks.forEach(t => {
   303→    if (t.startDate) {
   304→      const [year, month, day] = t.startDate.split('-').map(Number);
   305→      const date = new Date(year, month - 1, day);
   306→      if (!projectStart || date < projectStart) {
   307→        projectStart = date;
   308→      }
   309→    }
   310→  });
   311→
   312→  if (!projectStart) return 0;
   313→
   314→  // Build schedules
   315→  const graph = buildDependencyGraph(allTasks);
   316→  const schedules = forwardPass(allTasks, projectStart, graph);
   317→  backwardPass(allTasks, schedules, graph);
   318→
   319→  const schedule = schedules.get(task.id);
   320→  return schedule ? schedule.slack : 0;
   321→}
